import uasyncio as asyncio
import json
from machine import Pin
import network
import usocket as socket

# Set up access point
ap = network.WLAN(network.AP_IF)
ap.active(True)
ap.config(essid='ESP32_AP', password='12345678')

# LED pin
led = Pin(2, Pin.OUT)

async def websocket_handler(reader, writer):
    print("New client connection")
    try:
        # Handshake
        request = await reader.read(1024)
        headers = request.decode().split('\r\n')
        for header in headers:
            if 'Sec-WebSocket-Key' in header:
                ws_key = header.split(': ')[1]
        
        accept_key = websocket_accept_key(ws_key)
        response = (
            'HTTP/1.1 101 Switching Protocols\r\n'
            'Upgrade: websocket\r\n'
            'Connection: Upgrade\r\n'
            f'Sec-WebSocket-Accept: {accept_key}\r\n\r\n'
        )
        writer.write(response.encode())
        await writer.drain()

        # Handle WebSocket frames
        while True:
            frame = await reader.read(1024)
            if not frame:
                print("Client disconnected")
                break

            decoded_frame = frame[2:-1].decode()  # Simplified frame decoding
            try:
                command = json.loads(decoded_frame)
                if command.get("action") == "turn_on":
                    led.value(1)
                elif command.get("action") == "turn_off":
                    led.value(0)
                # Add more command handling as needed
                response_msg = json.dumps({"status": "success"})
            except json.JSONDecodeError:
                response_msg = json.dumps({"status": "error", "message": "Invalid JSON"})

            writer.write(bytes([0x81, len(response_msg)]) + response_msg.encode())
            await writer.drain()

    except Exception as e:
        print("Error:", e)
    finally:
        await writer.close()

def websocket_accept_key(key):
    import ubinascii
    import hashlib
    GUID = '258EAFA5-E914-47DA-95CA-C5AB0DC85B11'
    accept = key + GUID
    accept = hashlib.sha1(accept.encode()).digest()
    return ubinascii.b2a_base64(accept).strip().decode()

async def main():
    server = await asyncio.start_server(websocket_handler, '0.0.0.0', 8080)
    print("WebSocket server started")
    await server.serve_forever()

asyncio.run(main())